import { Ripple } from "primereact/ripple";
import { useNavigate } from "react-router-dom";
import {isValidElement, useMemo, useState} from "react";
import { type IMenuItem } from "@lmb-it/kitsconcerto-types";
import {Box, Flex} from "../../_compat";
import { useLanguage } from "../../_compat";

/* =======================
   Linking (UNCHANGED)
======================= */

const Linking = ({ icon, title, path, currentRoute }: IMenuItem & { currentRoute: string }) => {
    const navigate = useNavigate();
    const { t, isKeyExists } = useLanguage();

    const realPath = !path ? "/" : path;
    const isCurrent = currentRoute === path;

    const classesNames = useMemo(() => {
        let classes =
            "nav-link p-ripple flex align-items-center cursor-pointer p-2 mb-1 border-round transition-all transition-duration-200 w-full";
        if (isCurrent) {
            classes += " nav-link-active font-bold text-primary surface-100";
        } else {
            classes += " font-medium text-700 hover:surface-100";
        }
        return classes;
    }, [isCurrent]);

    function toCamelCase(title: string) {
        return title
            .toLowerCase()
            .split(" ")
            .map((word: string, index: number) =>
                index === 0 ? word : word.charAt(0).toUpperCase() + word.slice(1)
            )
            .join("");
    }

    const key = toCamelCase(title);

    return (
        <li>
            <a
                className={classesNames}
                onClick={() => realPath && navigate(realPath.toString())}
            >
                <Flex gap={10} alignItems={"center"}>
                    <Flex aspectRatio={1} w={15}>{isValidElement(icon) && icon}</Flex>
                    <span className="font-normal">
                        {isKeyExists(key) ? t(key) : title}
                    </span>
                </Flex>
                <Ripple />
            </a>
        </li>
    );
};

/* =======================
   NavItem (UPDATED)
======================= */

const NavItem = ({ icon, title, links, path, collapsable = true, defaultOpen = false, currentRoute }: IMenuItem & { currentRoute: string }) => {
    const { t } = useLanguage();
    const [isOpen, setIsOpen] = useState(defaultOpen);

    const hidden = (routes: IMenuItem[]) => !!routes?.every(item => item.hide);

    return (
        <li>
            {/* HEADER */}
            {collapsable && <div
                className="nav-header p-ripple p-2 mt-2 mb-1 border-round flex align-items-center justify-content-between text-500 hover:text-700 cursor-pointer transition-colors transition-duration-200 uppercase text-xs tracking-wide font-bold"
                onClick={() => setIsOpen(prev => !prev)}
            >
                <span>{t(title)}</span>

                <Flex gap={2} alignItems="center">
                    {icon && <i className={`pi ${icon} text-sm`}></i>}
                    <i
                        className={`pi pi-chevron-right text-xs transition-transform ${
                            isOpen ? "rotate-90" : ""
                        }`}
                    />
                </Flex>

                <Ripple/>
            </div>}
            {!collapsable && <div
                className="nav-header p-2 mt-2 mb-1 flex align-items-center justify-content-between text-500 uppercase text-xs tracking-wide font-bold"
            >
                <span>{t(title)}</span>
            </div>}

            {/* CHILDREN */}
            {/* CHILDREN */}
            {links && links.length > 0 && !hidden(links) && (
                <div
                    className={`nav-children-wrapper ${isOpen || !collapsable ? "open" : ""}`}
                >
                    <ul className="list-none p-0 ml-2">
                        {links.map((subItem, subIndex) => {
                            if (subItem.hide) return null;

                            if (subItem.links && subItem.links.length > 0 && !hidden(subItem.links)) {
                                return (
                                    <NavItem
                                        key={subIndex}
                                        currentRoute={currentRoute}
                                        {...subItem}
                                        path={`${path}/${subItem.path}`}
                                    />
                                );
                            }

                            if (subItem.element) {
                                return (
                                    <Linking
                                        key={subIndex}
                                        currentRoute={currentRoute}
                                        {...subItem}
                                        path={`${path}/${subItem.path}`}
                                    />
                                );
                            }

                            return null;
                        })}
                    </ul>
                </div>
            )}

        </li>
    );
};

/* =======================
   NavList (UNCHANGED)
======================= */

export const NavList = ({ items, currentRoute }: { items: IMenuItem[]; currentRoute: string }) => {
    return (
        <Box as={'ul'} p={[0,0,0,13]} className="list-none" gap={'5px'}>
            {items.map((item, index) => {
                if (item.hide) return null;

                if (item.links && item.links.length > 0) {
                    return (
                        <NavItem
                            key={index}
                            currentRoute={currentRoute}
                            {...item}
                        />
                    );
                }

                if (item.element) {
                    return (
                        <Linking
                            key={index}
                            currentRoute={currentRoute}
                            {...item}
                        />
                    );
                }

                return null;
            })}
        </Box>
    );
};
